//table on project reports page
import React from "react";
import {
  Box,
  Paper,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Typography,
  IconButton,
  Tooltip,
  Chip,
  CircularProgress,
  Button,
} from "@mui/material";
import {
  Download as DownloadIcon,
  Edit as EditIcon,
  Description as DescriptionIcon,
  TableChart as TableChartIcon,
  PhotoLibrary as PhotoLibraryIcon,
} from "@mui/icons-material";
import { format } from "date-fns";

const ReportsList = ({
  reports,
  loading,
  error,
  category,
  onDownload,
  onPrint,
  onRevise,
  onViewImages,
  onViewCOC,
  onExportCSV,
  processingReport = { reportId: null, action: null },
}) => {
  const getCategoryTitle = () => {
    switch (category) {
      case "asbestos-assessment":
        return "Asbestos Assessment Reports";
      case "asbestos-removal-jobs":
        return "Air Monitoring and Clearances";
      case "fibre-id":
        return "Fibre ID Reports";
      case "fibre-count":
        return "Fibre Count Reports";
      default:
        return "Reports";
    }
  };

  const getStatusColor = (status) => {
    switch (status?.toLowerCase()) {
      case "complete":
      case "completed":
      case "approved":
      case "final":
        return "success";
      case "in progress":
      case "in_progress":
      case "pending approval":
      case "pending_approval":
      case "awaiting approval":
      case "awaiting_approval":
      case "pending review":
      case "pending_review":
      case "under review":
      case "under_review":
        return "warning";
      case "draft":
      case "preliminary":
        return "info";
      case "rejected":
      case "cancelled":
        return "error";
      default:
        return "default";
    }
  };

  const formatStatus = (status) => {
    if (!status) return "";

    // Handle common status formats
    const statusMap = {
      in_progress: "In Progress",
      pending_approval: "Pending Approval",
      awaiting_approval: "Awaiting Approval",
      completed: "Completed",
      approved: "Approved",
      draft: "Draft",
      submitted: "Submitted",
      rejected: "Rejected",
      cancelled: "Cancelled",
      pending_review: "Pending Review",
      under_review: "Under Review",
      final: "Final",
      preliminary: "Preliminary",
    };

    // Check if we have a direct mapping
    if (statusMap[status.toLowerCase()]) {
      return statusMap[status.toLowerCase()];
    }

    // Generic formatting: replace underscores with spaces and capitalize
    return status
      .replace(/_/g, " ")
      .replace(/\b\w/g, (char) => char.toUpperCase());
  };

  if (loading) {
    return (
      <Box sx={{ display: "flex", justifyContent: "center", p: 3 }}>
        <CircularProgress />
      </Box>
    );
  }

  if (error) {
    return (
      <Typography color="error" sx={{ p: 3 }}>
        {error}
      </Typography>
    );
  }

  if (!reports?.length) {
    return (
      <Paper sx={{ p: 3, textAlign: "center" }}>
        <Typography variant="h6" color="text.secondary" gutterBottom>
          No Reports Found
        </Typography>
        <Typography variant="body2" color="text.secondary">
          No {getCategoryTitle().toLowerCase()} are available for this project.
        </Typography>
      </Paper>
    );
  }

  return (
    <Paper sx={{ p: 3, px: { xs: 1.5, sm: 3 } }}>
      <Typography variant="h6" gutterBottom>
        {getCategoryTitle()}
      </Typography>

      <TableContainer>
        <Table>
          <TableHead>
            <TableRow sx={{ "&:hover": { backgroundColor: "transparent" } }}>
              <TableCell>Date</TableCell>
              <TableCell>Description</TableCell>
              <TableCell>Status</TableCell>
              <TableCell align="center">Actions</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {reports.map((report) => (
              <TableRow key={report.id}>
                <TableCell>
                  {format(new Date(report.date), "dd/MM/yyyy")}
                </TableCell>
                <TableCell>
                  <Typography
                    variant="body2"
                    sx={{ color: "black", fontWeight: 500 }}
                  >
                    {report.description}
                  </Typography>
                  {report.asbestosRemovalist && (
                    <Typography
                      variant="caption"
                      color="text.secondary"
                      display="block"
                      sx={{ mt: 0.5 }}
                    >
                      {report.asbestosRemovalist}
                    </Typography>
                  )}
                  {report.additionalInfo && !report.asbestosRemovalist && (
                    <Typography
                      variant="caption"
                      color="text.secondary"
                      display="block"
                    >
                      {report.additionalInfo}
                    </Typography>
                  )}
                  {report.revision !== undefined && (
                    <Typography
                      variant="caption"
                      display="block"
                      sx={{
                        mt: 0.5,
                        fontWeight: "medium",
                        color: report.revision > 0 ? "#ed6c02" : "#666",
                      }}
                    >
                      Revision {report.revision}
                    </Typography>
                  )}
                </TableCell>
                <TableCell>
                  <Chip
                    label={formatStatus(report.status)}
                    color={getStatusColor(report.status)}
                    size="small"
                  />
                </TableCell>
                <TableCell align="center">
                  <Box
                    sx={{ display: "flex", gap: 1, justifyContent: "center" }}
                  >
                    <Tooltip title="Download Report">
                      <IconButton
                        size="small"
                        onClick={() => onDownload(report)}
                        color="secondary"
                        disabled={
                          (processingReport.reportId === report.id ||
                            processingReport.reportId === report.data?._id ||
                            processingReport.reportId === report.data?.id) &&
                          processingReport.action === "download"
                        }
                      >
                        {(processingReport.reportId === report.id ||
                          processingReport.reportId === report.data?._id ||
                          processingReport.reportId === report.data?.id) &&
                        processingReport.action === "download" ? (
                          <CircularProgress size={20} />
                        ) : (
                          <DownloadIcon />
                        )}
                      </IconButton>
                    </Tooltip>
                    {[
                      "clearance",
                      "asbestos_assessment",
                      "lead_clearance",
                      "lead_assessment",
                      "residential_asbestos_assessment",
                    ].includes(report.type) &&
                      onViewImages && (
                        <Tooltip title="View Report Images">
                          <IconButton
                            size="small"
                            onClick={() => onViewImages(report)}
                            color="primary"
                          >
                            <PhotoLibraryIcon />
                          </IconButton>
                        </Tooltip>
                      )}
                    {/* CSV Export button for air monitoring reports */}
                    {report.type === "shift" && onExportCSV && (
                      <Tooltip title="Export to CSV">
                        <IconButton
                          size="small"
                          onClick={() => onExportCSV(report)}
                          color="success"
                          disabled={
                            (processingReport.reportId === report.id ||
                              processingReport.reportId === report.data?._id ||
                              processingReport.reportId === report.data?.id) &&
                            processingReport.action === "csv"
                          }
                        >
                          {(processingReport.reportId === report.id ||
                            processingReport.reportId === report.data?._id ||
                            processingReport.reportId === report.data?.id) &&
                          processingReport.action === "csv" ? (
                            <CircularProgress size={20} />
                          ) : (
                            <TableChartIcon />
                          )}
                        </IconButton>
                      </Tooltip>
                    )}
                    {/* COC button for fibre ID and fibre count reports */}
                    {(category === "fibre-id" || category === "fibre-count") &&
                      (report.data?.chainOfCustody ||
                        report.chainOfCustody) &&
                      onViewCOC && (
                        <Tooltip title="View Chain of Custody">
                          <IconButton
                            size="small"
                            onClick={() => onViewCOC(report)}
                            color="info"
                          >
                            <DescriptionIcon />
                          </IconButton>
                        </Tooltip>
                      )}
                    {/* Only show revise button for completed reports (include shift_complete for air mon shift reports) */}
                    {(report.status === "complete" ||
                      report.status === "completed" ||
                      report.status === "Completed" ||
                      report.status === "shift_complete") &&
                      onRevise && (
                        <Button
                          size="small"
                          variant="outlined"
                          color="warning"
                          onClick={() => onRevise(report)}
                          startIcon={<EditIcon />}
                        >
                          Revise
                        </Button>
                      )}
                  </Box>
                </TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>
    </Paper>
  );
};

export default ReportsList;
